class Solution {
public:
bool solve(vector<int>& cookies, int people) {
	int total = 0;
	for (int i = 0; i < cookies.size(); i++) {
		total += cookies[i];
	}
	int min_share = total / people;
	int max_share = min_share;
	while (max_share - min_share > 1) {
		int mid_share = (max_share + min_share) / 2;
		if (total % people == 0 || total % people >= mid_share) {
			min_share = mid_share;
		} else {
			max_share = mid_share;
		}
	}
	return (total % people >= min_share);
}
};

int main() {
	Solution solution;
	int num_cookies;
	cin >> num_cookies;
	vector<int> cookies(num_cookies);
	for (int &i : cookies) {
		cin >> i;
	}
	int num_people;
	cin >> num_people;
	cout << (solution.solve(cookies, num_people) ? '1' : '0') << endl;
	return 0;
}
